import{_ as t,C as i,o as e,c as n,a2 as r,b as s,w as l,a as h,E as d,a3 as E}from"./chunks/framework.CPS2WBiI.js";const m=JSON.parse('{"title":"学习路线","description":"","frontmatter":{},"headers":[],"relativePath":"guide/index.md","filePath":"guide/index.md","lastUpdated":null}'),c={name:"guide/index.md"};function p(_,a,u,g,b,A){const o=i("Mermaid");return e(),n("div",null,[a[1]||(a[1]=r('<h1 id="学习路线" tabindex="-1">学习路线 <a class="header-anchor" href="#学习路线" aria-label="Permalink to &quot;学习路线&quot;">​</a></h1><p>这套材料的目标不是把 veRL 的每个文件翻译一遍，而是让你能回答四个问题：一次样本怎样生成、奖励怎样落到 token、优势怎样变成梯度、模型新权重怎样回到推理引擎。</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p>本站绑定 veRL 提交 <code>e5687fce</code>，默认讲解 <code>trainer.use_v1=true</code> 的新训练器。阅读其他版本时，先看<a href="./version-boundary">版本边界</a>。</p></div><h2 id="一张图看完" tabindex="-1">一张图看完 <a class="header-anchor" href="#一张图看完" aria-label="Permalink to &quot;一张图看完&quot;">​</a></h2>',4)),(e(),s(E,null,{default:l(()=>[d(o,{id:"mermaid-14",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20A%5BLLM%20%E5%9F%BA%E7%A1%80%3Cbr%2F%3Etoken%20%2F%20log-prob%20%2F%20KV%20cache%5D%20--%3E%20B%5BRL%20%E5%9F%BA%E7%A1%80%3Cbr%2F%3Epolicy%20%2F%20reward%20%2F%20advantage%5D%0A%20%20%20%20B%20--%3E%20C%5BPPO%20%E4%B8%8E%20GRPO%3Cbr%2F%3E%E7%9B%AE%E6%A0%87%E5%87%BD%E6%95%B0%E5%92%8C%E4%BC%B0%E8%AE%A1%E5%99%A8%5D%0A%20%20%20%20C%20--%3E%20D%5B%E5%85%A5%E5%8F%A3%E4%B8%8E%E5%88%9D%E5%A7%8B%E5%8C%96%3Cbr%2F%3EHydra%20%2F%20Ray%20%2F%20Worker%5D%0A%20%20%20%20D%20--%3E%20E%5Brollout%20%E5%88%B0%20update%3Cbr%2F%3E%E4%B8%80%E6%AC%A1%E8%AE%AD%E7%BB%83%20step%5D%0A%20%20%20%20E%20--%3E%20F%5B%E9%85%8D%E7%BD%AE%E4%B8%8E%E5%A5%96%E5%8A%B1%E5%87%BD%E6%95%B0%3Cbr%2F%3E%E8%B7%91%E9%80%9A%E5%B0%8F%E5%AE%9E%E9%AA%8C%5D%0A%20%20%20%20F%20--%3E%20G%5Bprofiling%20%E4%B8%8E%E8%B0%83%E8%AF%95%3Cbr%2F%3E%E8%A7%A3%E9%87%8A%E7%93%B6%E9%A2%88%E5%92%8C%E6%95%85%E9%9A%9C%5D%0A"})]),fallback:l(()=>[...a[0]||(a[0]=[h(" Loading... ",-1)])]),_:1})),a[2]||(a[2]=r('<h2 id="四个阶段" tabindex="-1">四个阶段 <a class="header-anchor" href="#四个阶段" aria-label="Permalink to &quot;四个阶段&quot;">​</a></h2><h3 id="_1-建立最小理论模型" tabindex="-1">1. 建立最小理论模型 <a class="header-anchor" href="#_1-建立最小理论模型" aria-label="Permalink to &quot;1. 建立最小理论模型&quot;">​</a></h3><p>先读 <a href="/losh_has_blog/verl-learning/fundamentals/llm">LLM 与后训练</a> 和 <a href="/losh_has_blog/verl-learning/fundamentals/rl">强化学习基础</a>。你不需要先学完一门深度学习课程，但需要知道：</p><ul><li>模型给出的不是“文字”，而是下一个 token 的概率分布；</li><li>rollout 是按策略采样轨迹，训练是对已有轨迹重新计算概率并反向传播；</li><li>reward 是结果信号，advantage 才是“这次动作比基线好多少”的训练信号；</li><li>attention mask 与 response mask 决定哪些 token 真正参与统计和损失。</li></ul><p>检查点：能用自己的话解释 <code>response</code>、<code>old_log_prob</code>、<code>ref_log_prob</code>、<code>values</code>、<code>advantages</code> 的区别。</p><h3 id="_2-用算法给字段赋义" tabindex="-1">2. 用算法给字段赋义 <a class="header-anchor" href="#_2-用算法给字段赋义" aria-label="Permalink to &quot;2. 用算法给字段赋义&quot;">​</a></h3><p>接着读 <a href="/losh_has_blog/verl-learning/algorithms/ppo">PPO 与 GAE</a> 和 <a href="/losh_has_blog/verl-learning/algorithms/grpo-family">GRPO 与算法家族</a>。此时公式只服务于源码：看到 ratio、clip、KL 或 group normalization，能立刻知道输入字段和输出字段。</p><p>检查点：能解释为什么 rollout 通常要保留行为策略的概率信息，以及 GRPO 为什么要求同一 prompt 生成多个回答。</p><h3 id="_3-沿一次-step-读源码" tabindex="-1">3. 沿一次 step 读源码 <a class="header-anchor" href="#_3-沿一次-step-读源码" aria-label="Permalink to &quot;3. 沿一次 step 读源码&quot;">​</a></h3><p>不要从目录第一行开始。按下面的顺序阅读：</p><ol><li><a href="/losh_has_blog/verl-learning/internals/architecture">整体架构</a>：先确认进程、资源与数据通道；</li><li><a href="/losh_has_blog/verl-learning/internals/entry-and-init">入口与初始化</a>：找到对象何时建立；</li><li><a href="/losh_has_blog/verl-learning/internals/rollout-to-update">从推理到训练</a>：跟踪一批数据；</li><li><a href="/losh_has_blog/verl-learning/internals/data-structures">数据结构与组织</a>：补齐 TensorDict、TransferQueue、KVBatchMeta 与 DataProto；</li><li><a href="/losh_has_blog/verl-learning/internals/workers">Worker 与资源编排</a>：理解 Ray 角色和 GPU 放置。</li></ol><p>检查点：能从 <code>main_ppo.py</code> 追到 actor 更新，并指出数据在哪一步只传句柄、在哪一步真正被 worker 读取。</p><h3 id="_4-做一个可复现实验" tabindex="-1">4. 做一个可复现实验 <a class="header-anchor" href="#_4-做一个可复现实验" aria-label="Permalink to &quot;4. 做一个可复现实验&quot;">​</a></h3><p>按 <a href="/losh_has_blog/verl-learning/practice/configuration">配置方法</a> 建立最小配置，按 <a href="/losh_has_blog/verl-learning/practice/reward-function">奖励函数</a> 写纯函数和单元测试。遇到问题先用 <a href="/losh_has_blog/verl-learning/practice/debugging">调试与排障</a> 定位阶段，再用 <a href="/losh_has_blog/verl-learning/practice/profiling">性能采集</a> 证明瓶颈。</p><p>检查点：保存完整命令、解析后的配置、代码提交、环境版本、训练日志和关键指标；换机器后仍能说明实验差异来自哪里。</p><h2 id="推荐的阅读姿势" tabindex="-1">推荐的阅读姿势 <a class="header-anchor" href="#推荐的阅读姿势" aria-label="Permalink to &quot;推荐的阅读姿势&quot;">​</a></h2><p>在编辑器中同时打开网页与源码。每读完一节，做三件小事：画出输入输出、在源码中找到对应函数、用一条日志或断言验证自己的判断。只看类名很容易形成“好像懂了”的错觉；跟踪一条真实字段才会暴露边界条件。</p><p>下一步：<a href="./source-map">源码地图</a>。</p>',18))])}const B=t(c,[["render",p]]);export{m as __pageData,B as default};
